// Recupera o valor de pulsos salvo no fluxo (definido via Inject ou Dashboard)
let valorPulsos = flow.get('valorPulsos') || 0;

// Proteção contra disparos múltiplos ou valor zero
if (valorPulsos <= 0 || msg.payload === 1) return null;

// Funções de tempo (Síncrona para precisão de microssegundos e Asíncrona para milissegundos)
const delayMs = (ms) => new Promise(resolve => setTimeout(resolve, ms));
const delayUs = (us) => {
    const start = process.hrtime.bigint();
    const target = start + BigInt(us * 1000);
    while (process.hrtime.bigint() < target) { }
};

// Indica no Node-RED que está processando
node.status({ fill: "blue", shape: "dot", text: "Enviando..." });

(async function () {
    // --- 1. RESET (Saída 1 - GPIO 4) ---
    // Envia HIGH, espera 5ms, envia LOW
    node.send([{ payload: 1 }, null, null]);
    await delayMs(5);
    node.send([{ payload: 0 }, null, null]);
    await delayMs(5);

    // --- 2. PULSOS (Saída 2 - GPIO 2) ---
    for (let i = 1; i <= valorPulsos; i++) {
        // Liga Transistor (Pulsos)
        node.send([null, { payload: 1 }, null]);
        delayUs(2000); // 2ms ON

        // Desliga Transistor
        node.send([null, { payload: 0 }, null]);
        delayUs(2000); // 2ms OFF
    }

    // --- 3. ENVIO / FINALIZAÇÃO (Saída 3 - GPIO 5) ---
    // Envia HIGH, espera 5ms, envia LOW
    node.send([null, null, { payload: 1 }]);
    await delayMs(5);
    node.send([null, null, { payload: 0 }]);
    await delayMs(5);

    node.status({ fill: "green", shape: "dot", text: "Concluído: " + valorPulsos });
})();

return null;
